import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface LatestReading {
  systolic: number;
  diastolic: number;
  category: string;
}

interface WeeklyTrend {
  day: string;
  systolic: number;
  diastolic: number;
}

interface PressureTrend {
  systolic: number[];
  diastolic: number[];
}

interface WidgetData {
  latestReading: LatestReading;
  weeklyTrend: WeeklyTrend[];
  pressureTrend: PressureTrend;
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const data = response.data as WidgetData;
  const meta = response.meta as MetaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: meta.primaryColor }}>
              Blood Pressure Monitor
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Latest Reading
            </Typography>
            <Typography variant="h4" fontWeight={700}>
              {data.latestReading.systolic}/{data.latestReading.diastolic} mmHg
            </Typography>
            <Chip
              label={data.latestReading.category}
              sx={{ mt: 0.5, bgcolor: meta.accentColor, color: '#FFFFFF', fontWeight: 500 }}
            />
          </Box>

          <Box sx={{ width: '100%', height: 120 }}>
            <LineChart
              series={[
                {
                  data: data.pressureTrend.systolic,
                  color: meta.primaryColor,
                  label: 'Systolic',
                  showMark: false,
                },
                {
                  data: data.pressureTrend.diastolic,
                  color: meta.accentColor,
                  label: 'Diastolic',
                  showMark: false,
                },
              ]}
              xAxis={[
                {
                  data: data.weeklyTrend.map((trend) => trend.day),
                  hide: true,
                }
              ]}
              yAxis={[{ hide: true }]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>

          <Stack direction="row" spacing={0.5}>
            {data.weeklyTrend.slice(0, 5).map((trend, index) => (
              <Chip
                key={index}
                label={`${trend.day}: ${trend.systolic}/${trend.diastolic}`}
                sx={{ fontSize: '11px', px: 1, py: 0.5 }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
